function isRuleReferenceAnalysis(value = {}) {
  const mode = String(value.analysisMode || value.analysisService?.mode || value.analysisService?.id || "");
  return mode === "real-data-rule-reference";
}

function isFullRealAiAnalysis(value = {}) {
  if (isRuleReferenceAnalysis(value)) return false;
  const mode = String(value.analysisService?.mode || value.analysisService?.id || value.analysisMode || "");
  return mode === "real-provider" || mode === "real-ai-analysis";
}

