function getTermTitle(termKey) {
  return terms[termKey]?.title || "术语";
}

function getTermButtonLabel(termKey) {
  return `查看${getTermTitle(termKey)}解释`;
}

function renderTermButton(termKey) {
  const label = getTermButtonLabel(termKey);
  return `<button class="term-button" data-term="${escapeHtml(termKey)}" type="button" aria-label="${escapeHtml(label)}" title="${escapeHtml(label)}">i</button>`;
}

function hydrateTermButton(button) {
  const label = getTermButtonLabel(button?.dataset?.term || "");
  button.textContent = "i";
  button.title = label;
  if (typeof button.setAttribute === "function") {
    button.setAttribute("aria-label", label);
  }
}

