function getMarketName(market) {
  return { a: "A 股", hk: "港股", us: "美股" }[market];
}

function escapeHtml(value) {
  return String(value ?? "").replace(/[&<>"']/g, (character) => {
    return {
      "&": "&amp;",
      "<": "&lt;",
      ">": "&gt;",
      '"': "&quot;",
      "'": "&#39;",
    }[character];
  });
}

function getProfileAdjustment() {
  return {
    conservative: { upside: -6, sentiment: -6, valuation: 4, technical: -3 },
    aggressive: { upside: 6, sentiment: 5, valuation: -2, technical: 5 },
    balanced: { upside: 0, sentiment: 0, valuation: 0, technical: 0 },
  }[sanitizeRiskProfile(state.riskProfile)];
}

function clamp(value, min = 0, max = 100) {
  return Math.max(min, Math.min(max, value));
}

function parsePositiveNumber(value) {
  const text = String(value ?? "").trim();
  if (!text) return null;
  const number = Number(text);
  return Number.isFinite(number) && number > 0 ? number : null;
}

function persistSelection() {
  localStorage.setItem("selectedMarket", state.selectedMarket);
  localStorage.setItem("selectedStockCode", state.selectedStock.code);
  if (state.selectedStock?.isMetadataOnly) {
    localStorage.setItem(
      "selectedStockMetadata",
      JSON.stringify({
        code: state.selectedStock.code,
        name: state.selectedStock.name,
        market: state.selectedStock.market,
        source: "metadata-only-catalog",
      }),
    );
  } else {
    localStorage.removeItem("selectedStockMetadata");
  }
}

const backgroundStatusSuppressionMs = 6000;

function showStatus(message, tone = "info", options = {}) {
  const now = Date.now();
  if (
    options.background &&
    showStatus.lastUserStatusAt &&
    now - showStatus.lastUserStatusAt < backgroundStatusSuppressionMs
  ) {
    return false;
  }
  if (!options.background) {
    showStatus.lastUserStatusAt = now;
  }
  elements.statusMessage.textContent = message;
  elements.statusMessage.className = `status-message is-visible ${tone}`;
  window.clearTimeout(showStatus.timer);
  showStatus.timer = window.setTimeout(() => {
    elements.statusMessage.className = "status-message";
    elements.statusMessage.textContent = "";
  }, 5000);
  return true;
}

function getApiConfig() {
  const savedBaseUrl = (localStorage.getItem("apiBaseUrl") || state.apiBaseUrl || defaultApiBaseUrl).trim();
  return {
    mode: sanitizeApiMode(localStorage.getItem("apiMode") || state.apiMode),
    baseUrl: savedBaseUrl.replace(/\/+$/, "") || defaultApiBaseUrl,
  };
}

function getApiConnectionLabel(config = getApiConfig()) {
  if (config.baseUrl) return config.baseUrl;
  if (isPublicSameOriginWebHost()) return "同源 /api";
  return "未配置";
}

function shouldUseBackendDataSource() {
  const config = getApiConfig();
  return config.mode === "backend" && localStorage.getItem("apiHealthStatus") === "connected";
}

function getAiModelCooldown() {
  const until = Number(localStorage.getItem("aiModelCooldownUntil") || 0);
  const remainingMs = Math.max(0, until - Date.now());
  return {
    active: remainingMs > 0,
    remainingMs,
    remainingMinutes: Math.max(1, Math.ceil(remainingMs / 60000)),
  };
}

function startAiModelCooldown(error = {}) {
  const code = String(error.code || "").toUpperCase();
  const message = String(error.message || "").toUpperCase();
  if (!/RATE_LIMIT|QUOTA|429|INSUFFICIENT/.test(`${code} ${message}`)) return null;
  const until = Date.now() + AI_MODEL_COOLDOWN_MS;
  localStorage.setItem("aiModelCooldownUntil", String(until));
  return getAiModelCooldown();
}

function clearAiModelCooldown() {
  localStorage.removeItem("aiModelCooldownUntil");
}

function shouldTryBackendStockSearch() {
  const config = getApiConfig();
  if (config.mode === "backend" || localStorage.getItem("apiHealthStatus") === "connected") return true;
  return shouldAutoConnectBackendOnStartup();
}

function isLocalDevelopmentWebHost() {
  const location = window.location || {};
  const hostname = location.hostname || "";
  const port = String(location.port || "");
  return (
    (isLoopbackHostname(hostname) || isPrivateNetworkHostname(hostname)) &&
    (!port || (Number(port) >= 4173 && Number(port) <= 4190))
  );
}

function isPublicSameOriginWebHost() {
  const location = window.location || {};
  const hostname = location.hostname || "";
  return Boolean(hostname) && !isLoopbackHostname(hostname) && !isPrivateNetworkHostname(hostname);
}

function shouldAutoConnectBackendOnStartup() {
  const fetcher = window.fetch || globalThis.fetch;
  const config = getApiConfig();
  return (
    (typeof fetcher === "function" || isPublicPreviewRefresh()) &&
    (isLocalDevelopmentWebHost() || isPublicSameOriginWebHost()) &&
    config.baseUrl === defaultApiBaseUrl &&
    localStorage.getItem("apiMode") !== "local" &&
    localStorage.getItem("apiHealthStatus") !== "connected"
  );
}

function shouldRefreshConnectedBackendOnStartup() {
  const fetcher = window.fetch || globalThis.fetch;
  const config = getApiConfig();
  return (
    typeof fetcher === "function" &&
    (isLocalDevelopmentWebHost() || isPublicSameOriginWebHost()) &&
    config.mode === "backend" &&
    localStorage.getItem("apiHealthStatus") === "connected"
  );
}

function getProviderStatus() {
  return state.providerStatus || readJsonStorage("apiProviderStatus", null, sanitizeProviderStatus);
}

function sanitizePublicPreviewAccess(value) {
  if (!isPlainObject(value)) return null;
  const recommendedAccess = isPlainObject(value.recommendedAccess) ? value.recommendedAccess : {};
  const accessEntries = Array.isArray(value.accessEntries) ? value.accessEntries : [];
  const stableHosting = isPlainObject(value.stableHosting) ? value.stableHosting : {};
  const localFallback = isPlainObject(value.localFallback) ? value.localFallback : {};
  const watchdog = isPlainObject(value.watchdog) ? value.watchdog : {};
  const temporaryTunnel = isPlainObject(value.temporaryTunnel) ? value.temporaryTunnel : {};
  const healthGate = isPlainObject(value.healthGate) ? value.healthGate : {};
  const stabilityGate = isPlainObject(value.stabilityGate) ? value.stabilityGate : {};
  return {
    status: typeof value.status === "string" ? value.status : "unknown",
    currentOrigin: typeof value.currentOrigin === "string" ? value.currentOrigin : "",
    recommendedAccess: {
      mode: typeof recommendedAccess.mode === "string" ? recommendedAccess.mode : "",
      url: typeof recommendedAccess.url === "string" ? recommendedAccess.url : "",
      label: typeof recommendedAccess.label === "string" ? recommendedAccess.label : "",
      reason: typeof recommendedAccess.reason === "string" ? recommendedAccess.reason : "",
    },
    accessEntries: accessEntries
      .filter((entry) => isPlainObject(entry))
      .map((entry) => ({
        id: typeof entry.id === "string" ? entry.id : "",
        label: typeof entry.label === "string" ? entry.label : "",
        url: typeof entry.url === "string" ? entry.url : "",
        status: typeof entry.status === "string" ? entry.status : "unknown",
        available: entry.available === true,
        external: entry.external === true,
        scope: typeof entry.scope === "string" ? entry.scope : "",
        warning: typeof entry.warning === "string" ? entry.warning : "",
        nextStep: typeof entry.nextStep === "string" ? entry.nextStep : "",
      }))
      .slice(0, 5),
    temporaryTunnel: {
      enabled: temporaryTunnel.enabled === true,
      provider: typeof temporaryTunnel.provider === "string" ? temporaryTunnel.provider : "",
      warning: typeof temporaryTunnel.warning === "string" ? temporaryTunnel.warning : "",
    },
    watchdog: {
      ok: watchdog.ok === true,
      status: typeof watchdog.status === "string" ? watchdog.status : "",
      publicUrl: typeof watchdog.publicUrl === "string" ? watchdog.publicUrl : "",
      localFallbackUrl: typeof watchdog.localFallbackUrl === "string" ? watchdog.localFallbackUrl : "",
      updatedAt: typeof watchdog.updatedAt === "string" ? watchdog.updatedAt : "",
      stale: watchdog.stale === true,
      ageSeconds: Number.isFinite(Number(watchdog.ageSeconds)) ? Number(watchdog.ageSeconds) : null,
      healthCycleCount: Number.isFinite(Number(watchdog.healthCycleCount)) ? Number(watchdog.healthCycleCount) : 0,
      healthWindowSeconds: Number.isFinite(Number(watchdog.healthWindowSeconds))
        ? Number(watchdog.healthWindowSeconds)
        : 0,
      healthIterationCount: Number.isFinite(Number(watchdog.healthIterationCount))
        ? Number(watchdog.healthIterationCount)
        : 0,
      healthStartedAt: typeof watchdog.healthStartedAt === "string" ? watchdog.healthStartedAt : "",
      healthEndedAt: typeof watchdog.healthEndedAt === "string" ? watchdog.healthEndedAt : "",
      healthRequiredEndpoints: Array.isArray(watchdog.healthRequiredEndpoints)
        ? watchdog.healthRequiredEndpoints.filter((item) => typeof item === "string").slice(0, 8)
        : [],
      restartCount: Number.isFinite(Number(watchdog.restartCount)) ? Number(watchdog.restartCount) : 0,
      lastFailure: isPlainObject(watchdog.lastFailure) ? watchdog.lastFailure : null,
      transientFailureCount: Number.isFinite(Number(watchdog.transientFailureCount))
        ? Number(watchdog.transientFailureCount)
        : 0,
      localFallbackOk: watchdog.localFallbackOk === undefined ? null : watchdog.localFallbackOk === true,
      guidance: typeof watchdog.guidance === "string" ? watchdog.guidance : "",
    },
    stableHosting: {
      configured: stableHosting.configured === true,
      url: typeof stableHosting.url === "string" ? stableHosting.url : "",
      status: typeof stableHosting.status === "string" ? stableHosting.status : "unknown",
      nextStep: typeof stableHosting.nextStep === "string" ? stableHosting.nextStep : "",
      healthGatePassed: stableHosting.healthGatePassed === true,
      healthGatePassedAt: typeof stableHosting.healthGatePassedAt === "string" ? stableHosting.healthGatePassedAt : "",
      releaseReady: stableHosting.releaseReady === true,
    },
    localFallback: {
      url: typeof localFallback.url === "string" ? localFallback.url : "",
      status: typeof localFallback.status === "string" ? localFallback.status : "unknown",
      note: typeof localFallback.note === "string" ? localFallback.note : "",
    },
    healthGate: {
      durationSeconds: Number.isFinite(Number(healthGate.durationSeconds))
        ? Number(healthGate.durationSeconds)
        : 180,
      intervalSeconds: Number.isFinite(Number(healthGate.intervalSeconds))
        ? Number(healthGate.intervalSeconds)
        : 15,
      lastWindowSeconds: Number.isFinite(Number(healthGate.lastWindowSeconds))
        ? Number(healthGate.lastWindowSeconds)
        : 0,
      lastIterationCount: Number.isFinite(Number(healthGate.lastIterationCount))
        ? Number(healthGate.lastIterationCount)
        : 0,
      lastStartedAt: typeof healthGate.lastStartedAt === "string" ? healthGate.lastStartedAt : "",
      lastEndedAt: typeof healthGate.lastEndedAt === "string" ? healthGate.lastEndedAt : "",
      lastFailureType: typeof healthGate.lastFailureType === "string" ? healthGate.lastFailureType : "",
      requiredEndpointCoverage: healthGate.requiredEndpointCoverage === true,
      requiredEndpoints: Array.isArray(healthGate.requiredEndpoints)
        ? healthGate.requiredEndpoints.filter((item) => typeof item === "string").slice(0, 8)
        : [],
      standbyReadyCount: Number.isFinite(Number(healthGate.standbyReadyCount))
        ? Number(healthGate.standbyReadyCount)
        : 0,
      standbyConfiguredCount: Number.isFinite(Number(healthGate.standbyConfiguredCount))
        ? Number(healthGate.standbyConfiguredCount)
        : 0,
      standbyRequirementPassed: healthGate.standbyRequirementPassed === true,
      requirement: typeof healthGate.requirement === "string" ? healthGate.requirement : "",
    },
    stabilityGate: {
      externalUseReady: stabilityGate.externalUseReady === true,
      temporaryAccessReady: stabilityGate.temporaryAccessReady === true,
      temporaryAccessContinuouslyReady: stabilityGate.temporaryAccessContinuouslyReady === true,
      standbyReadyCount: Number.isFinite(Number(stabilityGate.standbyReadyCount))
        ? Number(stabilityGate.standbyReadyCount)
        : 0,
      standbyConfiguredCount: Number.isFinite(Number(stabilityGate.standbyConfiguredCount))
        ? Number(stabilityGate.standbyConfiguredCount)
        : 0,
      standbyRequirementPassed: stabilityGate.standbyRequirementPassed === true,
      stableHostedUrl: stabilityGate.stableHostedUrl === true,
      temporaryTunnel: stabilityGate.temporaryTunnel === true,
      continuousHealthPassed: stabilityGate.continuousHealthPassed === true,
      requiredDurationSeconds: Number.isFinite(Number(stabilityGate.requiredDurationSeconds))
        ? Number(stabilityGate.requiredDurationSeconds)
        : 180,
      monitorWindowSeconds: Number.isFinite(Number(stabilityGate.monitorWindowSeconds))
        ? Number(stabilityGate.monitorWindowSeconds)
        : 0,
      monitorIterationCount: Number.isFinite(Number(stabilityGate.monitorIterationCount))
        ? Number(stabilityGate.monitorIterationCount)
        : 0,
      requiredEndpointCoverage: stabilityGate.requiredEndpointCoverage === true,
      lastFailureType: typeof stabilityGate.lastFailureType === "string" ? stabilityGate.lastFailureType : "",
      blockers: Array.isArray(stabilityGate.blockers)
        ? stabilityGate.blockers.filter((item) => typeof item === "string" && item.trim()).slice(0, 5)
        : [],
      userMessage: typeof stabilityGate.userMessage === "string" ? stabilityGate.userMessage : "",
    },
    nextSteps: Array.isArray(value.nextSteps)
      ? value.nextSteps.filter((item) => typeof item === "string" && item.trim()).slice(0, 5)
      : [],
  };
}

