function getStockSearchSourceStatus(stock = state.selectedStock) {
  if (!stock) return state.stockSearchSourceStatus || "";
  const savedCode = localStorage.getItem("selectedStockSearchSourceCode");
  if (savedCode === stock.code) {
    return state.stockSearchSourceStatus || localStorage.getItem("selectedStockSearchSourceStatus") || "";
  }
  return state.stockSearchSourceStatus && state.selectedStock?.code === stock.code
    ? state.stockSearchSourceStatus
    : "";
}

function isRealCoverageValue(value) {
  const text = String(value || "").trim().toLowerCase();
  if (!text) return false;
  return !/(fixture|sample|mock|empty|missing|metadata-only|not-ready|no-real|no-fixture)/.test(text);
}

function hasRealSourceRef(stock, type) {
  return Boolean(
    stock?.sourceRefs?.some((ref) => {
      if (!isPlainObject(ref) || ref.type !== type) return false;
      const serialized = JSON.stringify(ref).toLowerCase();
      return !/(fixture|sample|mock)/.test(serialized);
    }),
  );
}

function getActiveProviderIssue(stock = state.selectedStock) {
  const key = providerIssueKey(stock);
  if (!key) return null;
  const issue = state.providerIssues?.[key];
  if (!issue) return null;
  if (Number(issue.expiresAt) <= Date.now()) {
    delete state.providerIssues[key];
    localStorage.setItem("providerIssues", JSON.stringify(state.providerIssues));
    return null;
  }
  return issue;
}

function isQuotaOrRateLimitMessage(message = "") {
  return /quota|rate limit|25 requests per day|free api requests|too many requests|频率限制|额度/i.test(
    String(message || ""),
  );
}

function summarizeAutoIngestionIssue(payload) {
  const sources = Array.isArray(payload?.sources) ? payload.sources : [];
  const blockedSources = sources.filter((source) => source?.status === "empty" && source.blocker);
  const quotaSources = blockedSources.filter((source) => isQuotaOrRateLimitMessage(source.blocker));
  const selectedSources = quotaSources.length ? quotaSources : blockedSources;
  if (!selectedSources.length) return null;
  const firstMessage = redactProviderMessage(selectedSources[0].blocker);
  const quotaLimited = quotaSources.length > 0;
  return {
    type: quotaLimited ? "quota-rate-limit" : "provider-empty",
    label: quotaLimited ? "额度限制" : "真实源空白",
    message: firstMessage,
    sources: selectedSources.map((source) => source.label || source.id || "真实数据源"),
    recordedAt: new Date().toISOString(),
    expiresAt: Date.now() + PROVIDER_ISSUE_COOLDOWN_MS,
  };
}

function persistProviderIssue(stock, issue) {
  const key = providerIssueKey(stock);
  if (!key || !issue) return;
  state.providerIssues = sanitizeProviderIssues({
    ...(state.providerIssues || {}),
    [key]: issue,
  });
  localStorage.setItem("providerIssues", JSON.stringify(state.providerIssues));
}

function clearProviderIssue(stock) {
  const key = providerIssueKey(stock);
  if (!key || !state.providerIssues?.[key]) return;
  delete state.providerIssues[key];
  localStorage.setItem("providerIssues", JSON.stringify(state.providerIssues));
}

function providerIssueToAutoIngestionPayload(stock, issue) {
  return {
    status: "provider-cooldown-empty",
    mode: "automatic-real-provider-run",
    market: stock.market,
    symbol: stock.code,
    realDataCount: 0,
    sourceCount: Math.max(1, issue.sources?.length || 1),
    sources: (issue.sources?.length ? issue.sources : ["真实数据源"]).map((source) => ({
      id: "providerCooldown",
      label: source,
      status: "empty",
      count: 0,
      blocker: `${issue.label}：${issue.message || "短时间内不重复请求 provider。"}`,
    })),
    disclaimer: "真实 provider 刚返回限额或空结果；短时间内不重复请求，不使用 mock/fixture/sample 兜底。",
  };
}

function formatDataFreshnessTime(value = "") {
  if (!value) return "";
  const parsed = Date.parse(value);
  if (!Number.isFinite(parsed)) return String(value).slice(0, 16);
  return new Date(parsed).toLocaleString("zh-CN", {
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
  });
}

function getLatestFreshnessValue(values = []) {
  const candidates = values
    .filter((value) => typeof value === "string" && value.trim())
    .map((value) => {
      const parsed = Date.parse(value);
      return {
        value: value.trim(),
        parsed: Number.isFinite(parsed) ? parsed : 0,
      };
    });
  if (!candidates.length) return "";
  return candidates.sort((a, b) => b.parsed - a.parsed)[0].value;
}

function getMacroFreshnessValue(macroContext = null) {
  if (!isPlainObject(macroContext)) return "";
  const source = isPlainObject(macroContext.source) ? macroContext.source : {};
  const provider = isPlainObject(macroContext.provider) ? macroContext.provider : {};
  const indicators = Array.isArray(macroContext.indicators) ? macroContext.indicators : [];
  const policyEvents = Array.isArray(macroContext.policyEvents) ? macroContext.policyEvents : [];
  return getLatestFreshnessValue([
    macroContext.updatedAt,
    macroContext.asOf,
    macroContext.generatedAt,
    source.updatedAt,
    source.asOf,
    provider.updatedAt,
    ...indicators.map((item) => item?.asOf || item?.updatedAt),
    ...policyEvents.map((item) => item?.publishedAt || item?.asOf || item?.updatedAt),
  ]);
}

function buildFreshnessItem(label, freshness, ready, fallbackReadyText = "更新时间待确认") {
  if (freshness) return `${label}更新：${freshness}`;
  return `${label}更新：${ready ? fallbackReadyText : "待真实数据"}`;
}

function renderStockCoverageNote(stock = state.selectedStock, analysisState = null) {
  if (!elements.stockCoverageNote || !stock) return;
  const searchSourceStatus = getStockSearchSourceStatus(stock);
  const marketDataCoverage = stock.inputCoverage?.marketData || stock.marketDataCoverage;
  const providerIssue = getActiveProviderIssue(stock);
  const newsCoverage = getCurrentStockNewsCoverage(stock);
  const quotaLimited = providerIssue?.type === "quota-rate-limit";
  const hasRealQuoteOrHistorySource = hasRealHistorySource(stock.historySource);
  const quoteReady =
    stock.source?.type === "real-provider-quote" ||
    hasRealMarketQuoteCoverage(stock) ||
    hasRealQuoteOrHistorySource ||
    isRealCoverageValue(marketDataCoverage?.quote || marketDataCoverage);
  const historyReady =
    isRealCoverageValue(marketDataCoverage?.history || marketDataCoverage?.historyStatus) ||
    (typeof marketDataCoverage === "string" && /history/i.test(marketDataCoverage)) ||
    (hasRealQuoteOrHistorySource && normalizeHistoryPoints(stock.history).length >= 2);
  const newsReady =
    newsCoverage.newsReady ||
    newsCoverage.statementReady ||
    isRealCoverageValue(stock.inputCoverage?.news) ||
    hasRealSourceRef(stock, "news");
  const filingsReady =
    newsCoverage.filingsReady ||
    isRealCoverageValue(stock.inputCoverage?.filings) ||
    hasRealSourceRef(stock, "filing");
  const macroReady = isRealCoverageValue(stock.inputCoverage?.macro) || hasRealSourceRef(stock, "macro");
  const quoteFreshness = quoteReady
    ? formatDataFreshnessTime(stock.source?.updatedAt) ||
      formatDataFreshnessTime(stock.historySource?.updatedAt)
    : "";
  const newsFreshness = formatDataFreshnessTime(newsCoverage.newsLastUpdated || newsCoverage.lastUpdated);
  const filingsFreshness = formatDataFreshnessTime(newsCoverage.filingsLastUpdated);
  const statementFreshness = formatDataFreshnessTime(newsCoverage.statementLastUpdated);
  const macroFreshness =
    formatDataFreshnessTime(stock.macroContextFreshness || getMacroFreshnessValue(stock.macroContext)) ||
    (macroReady ? "provider 最新可见周期" : "");
  const analysisReady = analysisState?.status === "ready" && analysisState?.source === "backend";
  const ruleReferenceReady = analysisReady && isRuleReferenceAnalysis(stock);
  const fullAiReady = analysisReady && isFullRealAiAnalysis(stock);
  const aiService = getAiServiceStatus();
  const aiProviderAdapter = aiService?.providerAdapter;
  const realAiRuntimeReady =
    aiService?.mode === "real-provider" || canCallAnyConfiguredAiModel(aiService);
  const ruleReferenceValue = ruleReferenceReady
    ? "已生成"
    : fullAiReady
      ? "未单独生成"
      : "待真实数据";
  const fullAiValue = fullAiReady
    ? "已生成"
    : ruleReferenceReady
      ? "未生成"
      : realAiRuntimeReady
        ? "可检测"
        : aiProviderAdapter?.configured
          ? "待启用模型"
          : "待配置模型";
  const hasAnyRealCoverage = quoteReady || newsReady || filingsReady || macroReady || analysisReady;
  const identifyLabel =
    hasAnyRealCoverage
      ? "股票已识别"
      : searchSourceStatus === "metadata-only-catalog"
        ? "代码目录识别"
        : "股票识别已完成";
  const identifyTone = hasAnyRealCoverage || searchSourceStatus !== "metadata-only-catalog" ? "ready" : "limited";
  const items = [
    { label: "股票", value: identifyLabel, tone: identifyTone },
    { label: "行情", value: quoteReady ? (historyReady ? "已连接" : "已连接 / 缺历史走势") : quotaLimited ? "额度限制" : "待真实数据", tone: quoteReady ? "ready" : "limited" },
    { label: "新闻", value: newsReady ? "已连接" : newsCoverage.issueLabel || (quotaLimited ? "额度限制" : "待真实数据"), tone: newsReady ? "ready" : "limited" },
    { label: "公告", value: filingsReady ? "已连接" : "待真实数据", tone: filingsReady ? "ready" : "limited" },
    { label: "宏观", value: macroReady ? "已连接" : "待真实数据", tone: macroReady ? "ready" : "limited" },
    { label: "规则参考", value: ruleReferenceValue, tone: ruleReferenceReady || fullAiReady ? "ready" : "limited" },
    { label: "完整 AI", value: fullAiValue, tone: fullAiReady || realAiRuntimeReady ? "ready" : "limited" },
  ];
  const freshnessItems = [
    buildFreshnessItem("行情", quoteFreshness, quoteReady),
    buildFreshnessItem("新闻", newsFreshness, newsReady),
    buildFreshnessItem("公告", filingsFreshness, filingsReady),
    buildFreshnessItem("宏观", macroFreshness, macroReady, "最新可见周期待确认"),
    statementFreshness ? `公开言论更新：${statementFreshness}` : "",
  ].filter(Boolean);
  const summary =
    providerIssue
      ? `${providerIssue.label}：${providerIssue.message || "真实 provider 暂无可展示数据。"} 已保持空白，不使用样例数据。`
      : ruleReferenceReady
        ? "真实数据规则参考已生成；完整 AI 未生成。未连接项保持空白。"
      : hasAnyRealCoverage
        ? "当前股票数据覆盖如下，未连接项保持空白。"
        : searchSourceStatus === "metadata-only-catalog"
      ? "当前股票仅由代码目录识别，行情、新闻、公告、宏观和 AI 分析仍需真实数据源。"
        : "严格真实数据模式：等待真实行情、新闻、公告、宏观和 AI 分析。";

  elements.stockCoverageNote.className = `stock-coverage-note ${
    hasAnyRealCoverage ? "is-ready" : "is-limited"
  }`;
  elements.stockCoverageNote.innerHTML = `
    <span class="coverage-summary">${escapeHtml(summary)}</span>
    <span class="coverage-chip-row">
      ${items
        .map(
          (item) => `
            <span class="coverage-chip is-${item.tone}">
              <strong>${escapeHtml(item.label)}</strong>
              <span>${escapeHtml(item.value)}</span>
            </span>
          `,
        )
        .join("")}
    </span>
    <span class="coverage-freshness-row" aria-label="数据更新时间">
      ${freshnessItems.map((item) => `<span>${escapeHtml(item)}</span>`).join("")}
    </span>
  `;
  if (!elements.stockCoverageNote.querySelector) {
    elements.stockCoverageNote.textContent = `${summary} ${items
      .map((item) => `${item.label} ${item.value}`)
      .join(" ")} ${freshnessItems.join(" ")}`;
  }
}

