async function saveLocalAiModelConfig(form) {
  if (!form) return;
  const submitButton = form.querySelector("button[type='submit']");
  const formData = new FormData(form);
  const apiKey = String(formData.get("apiKey") || "").trim();
  const provider = String(formData.get("provider") || "").trim() || "openai-compatible";
  const apiStyle = String(formData.get("apiStyle") || "").trim() || "chat-completions";
  const slot = String(formData.get("slot") || "").trim() || "primary";
  const modelId = String(formData.get("modelId") || "").trim() || "gpt-5.5";
  const baseUrl =
    String(formData.get("baseUrl") || "").trim() ||
    "https://generativelanguage.googleapis.com/v1beta/openai";
  if (!apiKey) {
    showStatus("请先粘贴模型 API key。", "warning");
    return;
  }
  if (submitButton) {
    submitButton.disabled = true;
    submitButton.textContent = "保存中";
  }
  try {
    await requestApi("/api/ai-services/local-model-config", {
      method: "POST",
      body: { apiKey, provider, modelId, baseUrl, apiStyle, slot },
    });
    clearAiModelCooldown();
    localStorage.removeItem("lastAiProviderRelay");
    form.reset();
    const keyInput = form.querySelector("input[name='apiKey']");
    const modelInput = form.querySelector("input[name='modelId']");
    const baseUrlInput = form.querySelector("input[name='baseUrl']");
    const providerInput = form.querySelector("input[name='provider']");
    const apiStyleInput = form.querySelector("input[name='apiStyle']");
    const slotInput = form.querySelector("[name='slot']");
    if (keyInput) keyInput.value = "";
    if (modelInput) modelInput.value = modelId;
    if (baseUrlInput) baseUrlInput.value = baseUrl;
    if (providerInput) providerInput.value = provider;
    if (apiStyleInput) apiStyleInput.value = apiStyle;
    if (slotInput) slotInput.value = slot;
    const aiService = await loadAiServiceStatus();
    renderAiServiceState(
      "connected",
      canCallAnyConfiguredAiModel(aiService)
        ? `真实 AI 模型已配置为 ${getActiveAiModelLabel(aiService)}，可以进行本机 smoke。`
        : "模型配置已提交，但后端仍未返回可调用状态。",
    );
    await loadAnalysis();
    showStatus(
      slot.startsWith("fallback")
        ? `备用 AI 模型 key 已保存到 ${slot}，页面已重新检测 AI 状态。`
        : "本机 AI 主模型 key 已保存，页面已重新检测 AI 状态。",
      "success",
    );
  } catch (error) {
    showStatus(`AI 模型配置失败：${error.message}`, "warning");
  } finally {
    if (submitButton) {
      submitButton.disabled = false;
      submitButton.textContent = "保存到本机运行时";
    }
  }
}

function applyAiModelProviderPreset(selectElement) {
  const form = selectElement?.closest("[data-local-ai-model-config]");
  const preset = freeAiModelProviderPresets[selectElement?.value] || freeAiModelProviderPresets["openai-primary"];
  if (!form || !preset) return;
  const providerInput = form.querySelector("input[name='provider']");
  const apiStyleInput = form.querySelector("input[name='apiStyle']");
  const slotInput = form.querySelector("[name='slot']");
  const modelInput = form.querySelector("input[name='modelId']");
  const baseUrlInput = form.querySelector("input[name='baseUrl']");
  const keyInput = form.querySelector("input[name='apiKey']");
  if (providerInput) providerInput.value = preset.provider;
  if (apiStyleInput) apiStyleInput.value = preset.apiStyle;
  if (slotInput) slotInput.value = preset.slot || "primary";
  if (modelInput) modelInput.value = preset.modelId;
  if (baseUrlInput) baseUrlInput.value = preset.baseUrl;
  if (keyInput) {
    keyInput.placeholder =
      selectElement.value === "gemini-free"
        ? "粘贴 Gemini API key，只提交到本机后端"
        : selectElement.value === "openrouter-free"
          ? "粘贴 OpenRouter API key，只提交到本机后端"
          : selectElement.value === "groq-free"
            ? "粘贴 Groq API key，只提交到本机后端"
        : selectElement.value === "openai-primary"
          ? "粘贴 OpenAI API key，只提交到本机后端"
          : "粘贴模型 API key，只提交到本机后端";
  }
  showStatus(`已选择 ${preset.label}：${preset.note}`, "info");
}

