function renderProviderOperationalSummary(provider) {
  if (!provider) {
    return `
      <div class="provider-operational-summary">
        <div>
          <strong>数据源状态未返回</strong>
          <span>后端已连接，但尚未拿到 provider 明细。</span>
        </div>
      </div>
    `;
  }

  const registry = provider.providerRegistry;
  const integrationPlan = provider.integrationPlan;
  const activeChannels = Array.isArray(provider.activeRealChannels) ? provider.activeRealChannels : [];
  const marketQuoteReady =
    provider.realtimeStatus?.marketQuote === "real-provider-enabled" ||
    activeChannels.includes("twelve-data-quote") ||
    activeChannels.includes("alpha-vantage-quote") ||
    activeChannels.includes("free-api-relay");
  const newsReady =
    provider.realtimeStatus?.news === "provider-path-enabled-empty-on-error" ||
    activeChannels.includes("alpha-vantage-news") ||
    activeChannels.includes("yahoo-finance-rss");
  const macroReady =
    provider.realtimeStatus?.macro === "real-provider-enabled" ||
    provider.macroDataAdapter?.canFetchLiveMacro === true ||
    activeChannels.includes("world-bank-macro");
  const filingsReady = provider.realtimeStatus?.filings === "real-provider-enabled";
  const providerName = provider.name || provider.id || "Provider 未标注";
  const runtime = registry?.activeRuntimeProvider || provider.mode || "未标注";
  const requiredText = registry
    ? `${registry.readyRequiredCount}/${registry.requiredProviderCount}`
    : integrationPlan
      ? `${integrationPlan.configuredRequiredCount}/${integrationPlan.requiredSourceCount}`
      : "未返回";
  const missingGroups = registry?.selectedProviders?.length
    ? registry.selectedProviders
        .filter((item) => item.required && item.status !== "ready-for-adapter")
        .map((item) => item.label || item.groupId)
        .slice(0, 3)
    : [];
  const nextGap = missingGroups.length ? missingGroups.join(" / ") : "暂无必选 provider 缺口";
  const statusTone = provider.status?.includes("connected") ? "已连接" : provider.status || "状态未标注";
  const chips = [
    `行情 ${marketQuoteReady ? "已连接" : "待接入"}`,
    `新闻 ${newsReady ? "可请求/空白回退" : "待接入"}`,
    `公告 ${filingsReady ? "已连接" : "待接入"}`,
    `宏观 ${macroReady ? "已连接" : "待接入"}`,
  ];

  return `
    <div class="provider-operational-summary" aria-label="数据源关键状态">
      <div>
        <strong>${escapeHtml(providerName)}</strong>
        <span>${escapeHtml(statusTone)} · 运行时 ${escapeHtml(runtime)} · 必选 ${escapeHtml(requiredText)}</span>
      </div>
      <div class="provider-summary" aria-label="核心数据覆盖">
        ${chips.map((chip) => `<span>${escapeHtml(chip)}</span>`).join("")}
      </div>
      <p>${escapeHtml(nextGap === "暂无必选 provider 缺口" ? "关键数据通道正在按真实数据模式运行；未连接项保持空白。" : `下一步缺口：${nextGap}。`)}</p>
    </div>
  `;
}

function renderProviderDetailsPanel(provider) {
  return `
    ${renderProviderOperationalSummary(provider)}
    <details class="provider-advanced">
      <summary>技术详情与上线门禁</summary>
      <div class="provider-advanced-body">
        ${renderProviderDetails(provider)}
      </div>
    </details>
  `;
}

function renderNewsIntelligencePanel() {
  const records = state.newsIntelligenceRecords || [];
  const matchingRecords = records.filter((record) => {
    const symbolMatches = !record.symbol || record.symbol === state.selectedStock.code;
    const marketMatches = !record.market || record.market === state.selectedMarket;
    return symbolMatches && marketMatches;
  });
  const visibleRecords = (matchingRecords.length ? matchingRecords : records).slice(0, 3);
  const summary = records.length
    ? `已保存 ${records.length} 条新闻情报记录，当前股票匹配 ${matchingRecords.length} 条`
    : "暂未保存新闻情报记录";
  const statusMessage = state.newsIntelligenceMessage || "保存后可用于后续审计、回放和生产数据库迁移验证。";
  const disabled = state.newsIntelligenceStatus === "syncing" ? " disabled" : "";
  const recordMarkup = visibleRecords.length
    ? visibleRecords
        .map(
          (record) => `
            <span>${escapeHtml(record.symbol || "未标注")} · ${escapeHtml(record.title)} · 重要性 ${escapeHtml(String(record.importanceScore))}/100 · 可信度 ${escapeHtml(String(record.sourceCredibilityScore))}/100</span>
          `,
        )
        .join("")
    : "<span>暂无可展示的已保存记录</span>";

  return `
    <div class="provider-summary" aria-label="新闻情报持久化状态">
      <span>${escapeHtml(summary)}</span>
    </div>
    <div class="provider-summary" aria-label="新闻情报持久化说明">
      <span>${escapeHtml(statusMessage)}</span>
    </div>
    <div class="provider-actions" aria-label="新闻情报持久化操作">
      <button class="secondary-button" data-save-news-intelligence type="button"${disabled}>保存当前股票新闻情报</button>
      <button class="secondary-button" data-refresh-news-intelligence type="button"${disabled}>刷新已保存记录</button>
    </div>
    <div class="provider-capabilities" aria-label="新闻情报历史记录">${recordMarkup}</div>
  `;
}

